import json,re
for f in ['WhaleCloud-DocChain_0612','sourcery','dalpha-deepresearch','openai-deepresearch','grok-deeper-search','perplexity-Research']:
    for line in open(f+'.jsonl'):
        d=json.loads(line)
        if str(d.get('id'))=='72':
            a=d['article']
            secs=[l for l in a.split('\n') if re.match(r'^#+.*(synthes|debate|consensus|tension|convergen|contested|unresolved|open question|limitation|gap)',l,re.I)]
            labs=len(re.findall(r'^\*\*[A-Za-z][^*]{2,40}\*\*',a,re.M))
            print(f'{f:28s} bold-labels={labs:3d}  debate/synth-sections={len(secs)}')
            for s in secs[:3]: print('      ',s.strip()[:70])
            break
